# SARS-CoV-2 PDB Structure Coverage Analysis

Below is a complete Python script that queries the RCSB PDB API, extracts structure metadata, maps chains to SARS-CoV-2 proteome genes, and produces a coverage table and bar chart.

```python
#!/usr/bin/env python3
"""
SARS-CoV-2 PDB Structure Coverage Analysis
-------------------------------------------
Queries the RCSB PDB REST API for all SARS-CoV-2 structures, extracts
metadata, maps chains to proteome genes, and visualizes coverage.

Dependencies:
    pip install biopython requests pandas matplotlib
"""

import time
import json
import re
import requests
import pandas as pd
import matplotlib.pyplot as plt
from collections import defaultdict

# ----------------------------------------------------------------------
# Configuration & constants
# ----------------------------------------------------------------------
SEARCH_URL = "https://search.rcsb.org/rcsbsearch/v2/query"
DATA_GRAPHQL_URL = "https://data.rcsb.org/graphql"
ENTRY_REST_URL = "https://data.rcsb.org/rest/v1/core/entry/{pdb_id}"

# SARS-CoV-2 taxonomy ID (Severe acute respiratory syndrome coronavirus 2)
SARS_COV2_TAXID = 2697049

# Rate-limiting: RCSB recommends being courteous. We keep below ~1 req/sec
REQUEST_DELAY = 1.0          # seconds between calls
BATCH_SIZE = 50              # entries per GraphQL batch
SESSION = requests.Session()
SESSION.headers.update({"User-Agent": "SARS-CoV-2-Coverage/1.0 (research script)"})


# ----------------------------------------------------------------------
# Step 1: Query RCSB Search API for SARS-CoV-2 structures
# ----------------------------------------------------------------------
def fetch_sars_cov2_pdb_ids():
    """
    Use the RCSB Search API to retrieve all PDB entry IDs whose source
    organism is SARS-CoV-2 (taxonomy id 2697049).
    Handles pagination via the 'paginate' return option.
    """
    pdb_ids = []
    start = 0
    rows = 1000  # max page size allowed by RCSB

    while True:
        query = {
            "query": {
                "type": "terminal",
                "service": "text",
                "parameters": {
                    "attribute": "rcsb_entity_source_organism.taxonomy_lineage.id",
                    "operator": "exact_match",
                    "value": str(SARS_COV2_TAXID),
                },
            },
            "return_type": "entry",
            "request_options": {
                "paginate": {"start": start, "rows": rows},
                "results_content_type": ["experimental"],
            },
        }

        resp = SESSION.post(SEARCH_URL, json=query, timeout=60)
        time.sleep(REQUEST_DELAY)

        if resp.status_code == 204:
            # No (more) results
            break
        resp.raise_for_status()
        data = resp.json()

        result_set = data.get("result_set", [])
        if not result_set:
            break

        pdb_ids.extend([r["identifier"] for r in result_set])

        total = data.get("total_count", len(pdb_ids))
        start += rows
        if start >= total:
            break

    # de-duplicate while preserving order
    seen = set()
    unique_ids = []
    for pid in pdb_ids:
        if pid not in seen:
            seen.add(pid)
            unique_ids.append(pid)
    print(f"[INFO] Retrieved {len(unique_ids)} SARS-CoV-2 PDB entries.")
    return unique_ids


# ----------------------------------------------------------------------
# Step 2: Fetch metadata (resolution, method, chains, UniProt) via GraphQL
# ----------------------------------------------------------------------
def build_graphql_query(pdb_ids):
    """Construct a GraphQL query for a batch of entry IDs."""
    ids_json = json.dumps(pdb_ids)
    query = f"""
    {{
      entries(entry_ids: {ids_json}) {{
        rcsb_id
        rcsb_entry_info {{
          resolution_combined
          experimental_method
        }}
        exptl {{
          method
        }}
        polymer_entities {{
          rcsb_polymer_entity_container_identifiers {{
            auth_asym_ids
            uniprot_ids
          }}
          rcsb_polymer_entity {{
            pdbx_description
          }}
          uniprots {{
            rcsb_id
            rcsb_uniprot_protein {{
              name {{
                value
              }}
            }}
          }}
        }}
      }}
    }}
    """
    return query


def fetch_metadata(pdb_ids):
    """
    Fetch metadata for all PDB IDs in batches using the GraphQL Data API.
    Returns a list of per-entry record dicts.
    """
    records = []

    for i in range(0, len(pdb_ids), BATCH_SIZE):
        batch = pdb_ids[i : i + BATCH_SIZE]
        query = build_graphql_query(batch)

        resp = SESSION.post(DATA_GRAPHQL_URL, json={"query": query}, timeout=120)
        time.sleep(REQUEST_DELAY)
        resp.raise_for_status()
        payload = resp.json()

        entries = payload.get("data", {}).get("entries", []) or []
        for entry in entries:
            records.append(parse_entry(entry))

        print(f"[INFO] Processed {min(i + BATCH_SIZE, len(pdb_ids))}/{len(pdb_ids)} entries")

    return records


def parse_entry(entry):
    """Extract the fields of interest from a single GraphQL entry record."""
